var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"숲 속의 오두막집에 늙은 나무꾼이 살았습니다.","JPN":"むかしむかし、森の中の小屋に木こりのおじいさんが\\n暮らしていました。","ENG":"There was an old woodcutter who lived in a cabin in the middle of a forest.","TWN":"從前，在深林中小木屋裡住著一個老樵夫。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼은 손재주가 좋아 팔고 남은 나무를 깎아 인형을 만들어 내다팔곤 했어요.","JPN":"木こりは手先が器用だったので、余った木で\\n木彫り人形をつくり、売っていました。","ENG":"He was good with his hands. He carved dolls out of leftover wood and sold them at the market.","TWN":"樵夫手藝很好，他會把沒賣出去的木頭雕成人偶並拿出去賣。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"여느 때처럼 초를 켜고 나무를 깎던 나무꾼은 그날 아주 아름다운 인형을 만들었습니다.","JPN":"ある日、いつもどおりロウソクを灯して作業をしていた\\n木こりは、とても綺麗な人形を完成させました。","ENG":"Every night he'd carve wood by candlelight, and one day he created a very beautiful doll.","TWN":"有一天，樵夫把木頭雕成了一個非常美麗的人偶。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"보다 완벽한 인형은 앞으로 없을 거라 생각한 나무꾼은 그 인형을 파는 대신 간직하기로 했죠.","JPN":"これ以上の人形はつくれないだろうと思った木こりは、\\nその人形は売らずに自分のものにしようと思いました。","ENG":"He thought he could never make anything better than this, so he decided to keep it to himself.","TWN":"樵夫對自己的作品非常滿意，於是他沒有賣掉那個人偶，而是自己留著。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼의 인형에 대한 애착은 날이 갈수록 커져 인형이 사람이 되길 바랬습니다.","JPN":"人形に対する木こりの愛情は日増しにふくらんでいき、\\nやがてその人形が人間になることを願うようになりました。","ENG":"The woodcutter became obsessed with his doll, to the point that he wanted it to come to life.","TWN":"樵夫越來越喜愛人偶，他甚至希望人偶能變成真正的人。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 그는 산꼭대기의 요정을 찾아가 인형에게 자신의 생명을 나눠달라고 소원을 빌었어요.","JPN":"そして彼は山頂に住む妖精を訪ね、人形に\\n自分の命を分け与えるようにお願いをしました。","ENG":"He went to a fairy who lived on the top of the mountain, and pleaded with it to give some of his life to his doll.","TWN":"於是他去找了住在山頂的妖精，請求把自己的生命分給人偶。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"요정은 그 부탁을 들어주게 되면, 나무꾼은 5년 밖에 살지 못할 것이라고 했습니다.","JPN":"妖精は、その願いを叶えてしまうと木こりはこの先5年しか生きられないと告げました。","ENG":"The fairy said he could only live five more years if he shared his life with his doll.","TWN":"妖精說，如果自己接受這個請求，樵夫就會只剩下5年的壽命。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼에도 나무꾼은 흔쾌히 수락했습니다.","JPN":"しかし、木こりは喜んで受け入れました。","ENG":"The woodcutter happily said yes.","TWN":"但樵夫依舊非常欣喜地同意了。"},"stage":{"bg":"EV_SIGMA_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"소원을 빈 나무꾼이 집으로 돌아오자, 인형은 정말로 소녀가 되어 있었습니다.","JPN":"木こりが小屋に帰ると、人形は少女になっていました。","ENG":"When he came back to his cabin, his doll had become a girl.","TWN":"回到家後，樵夫發現人偶果真變成了少女。"},"stage":{"bg":"EV_SIGMA_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 인형일 적보다 훨씬 아름답고 사랑스러웠습니다.","JPN":"少女は人形だった頃よりも、美しく愛らしい姿でした。","ENG":"She was more beautiful and adorable than she was as a doll.","TWN":"少女比人偶更加美麗可人。"},"stage":{"bg":"EV_SIGMA_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼은 소녀를 자신의 딸처럼 여기며 성심껏 가르치고 보살폈습니다.","JPN":"木こりは少女を我が子のように可愛がり、面倒をみました。","ENG":"The woodcutter raised her as his own daughter, teaching and caring for her with utmost dedication.","TWN":"樵夫把少女當成自己的女兒，盡心盡力地照顧她教導她。"},"stage":{"bg":"EV_SIGMA_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"인형일 적부터 느껴온 애정이 소녀에겐 익숙했습니다.","JPN":"人形だった頃から感じていた愛情は、少女にとって\\n馴染み深いものでした。","ENG":"She was used to his affection that she'd felt since she was a doll.","TWN":"少女知道樵夫從人偶時期開始就對自己百般呵護。"},"stage":{"bg":"EV_SIGMA_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 자신을 만들어준 나무꾼을 아빠라고 부르며 따랐습니다.","JPN":"自分をつくってくれた木こりのことをパパと呼び、\\n自然と慕うようになりました。","ENG":"She called him Daddy and loved him as if he really was her father.","TWN":"於是她也把樵夫當作父親。"},"stage":{"bg":"EV_SIGMA_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 두 사람은 가족이 되었습니다.","JPN":"そうして、二人は家族になりました。","ENG":"Like that, they became family.","TWN":"兩個人就這樣成了一家人。"},"stage":{"bg":"EV_SIGMA_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"난 이 대목이 좋아.","JPN":"ボクはこのくだりが好きなんだ。","ENG":"I like this part,","TWN":"我喜歡這部分。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"피로 전혀 이어지지 않은 두 사람이 가족이 되는 것 말이야.","JPN":"血がつながってない二人が家族になるくだりね。","ENG":"where two strangers come together as family.","TWN":"兩個沒有任何血緣關係的人成為一家人了。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"부모님이 뭔지 알아?","JPN":"「親」の意味がわかる？","ENG":"Do you know what parents are?","TWN":"你知道什麼叫父母嗎？"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L27_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"널 이 세상에 태어날 수 있도록 도와준 사람이지.","JPN":"キミの誕生を手伝ってくれた人のことだよ。","ENG":"They're the ones who brought you into this world.","TWN":"就是讓你誕生在這個世界的人。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"사람에게만 부모가 있는 게 아냐.","JPN":"親がいるのは人間だけではない。","ENG":"It's not just people who have parents.","TWN":"並不是只有人類才有父母。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"모두에겐 부모가 있지.","JPN":"あらゆるものに親がいるんだ。","ENG":"So does everyone else.","TWN":"萬物都有自己的父母。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"심지어 나에게도 날 만들어준 부모가 있거든.","JPN":"ボクにだって、つくってくれた親がいるからね。","ENG":"Even I have parents who made me.","TWN":"甚至我也有父母。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L33_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"FL-R4-44625. 부모님이 나한테 지어준 이름이지.","JPN":"FL-R4-44625。親がつけてくれた、ボクの名前だよ。","ENG":"FL-R4-44625. That's the name my parents gave me.","TWN":"FL-R4-44625，是我的父母給我取的名字。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L34_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"FL은 가족사랑의 약자야. 애정이 듬뿍 느껴지지 않아?","JPN":"FLは、ファミリー・ラブのイニシャル。溢れんばかりの\\n愛情が感じられるだろ？","ENG":"FL stands for familial love. Can't you feel their affection in it?","TWN":"FL是家人之愛的簡寫，有沒有感覺到滿滿的愛意？"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"하지만 발음하기엔 영 별로니까, 날 부를 땐 편하게 R4라고 불러.","JPN":"でも、フルネームは呼びにくいから気楽に\\nR4と呼んでくれ。","ENG":"But since my name is too long to say all the time, you can just call me R4.","TWN":"但發音有些困難，你就叫我R4吧。"},"stage":{"bg":"black","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그건 그렇고, 네 이름은 뭐야?","JPN":"それはそうと、キミの名前は？","ENG":"By the way, what's your name?","TWN":"話說，你叫什麼名字？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......GAP – Σ – 1684 입니다.","JPN":"……甲 – Σ –1684 です。","ENG":"GAP-Σ-1684.","TWN":"……GAP – Σ – 1684。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L42_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그래, 시그마. 넌 그렇게 부르는 편이 좋겠네.","JPN":"シグマ、か。キミのことはそう呼んだほうが\\n良さそうだね。","ENG":"Alright, Sigma. I'm going to call you that.","TWN":"好，西格瑪。我就叫你西格瑪吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"시그마는 누가 자길 만들어줬는지 기억해?","JPN":"シグマは誰につくられたか覚えてる？","ENG":"Sigma, do you remember who made you?","TWN":"西格瑪，你知道是誰創造了你嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"물론입니다. 관리자님께서 저를 만들어주셨습니다.","JPN":"もちろんです。管理者が私をつくってくれました。","ENG":"Of course. The Administrator did.","TWN":"當然，是管理者大人創造了我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"흠, 관리자? 마치 공장장처럼 딱딱해서 별로 정은 안 가는 이름이네.","JPN":"ふうん、管理者か。「工場長」並みの堅苦しさだね。\\nあまり愛着が湧く名前じゃないな。","ENG":"The Administrator? That sounds way too businesslike.","TWN":"嗯，管理者？這個名字聽起來太冰冷了，我不喜歡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그냥 편의상 아빠라고 하자고.","JPN":"気楽に「パパ」ってことにしようよ。","ENG":"Why don't you call him Daddy instead?","TWN":"為方便起見，就叫他爸爸吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"뭐, 난 비록 태어나서 아빠를 만난 적이 한 번도 없긴 하지만......","JPN":"まあ、ボクは生まれてこの方パパに会ったことは\\nないけど……","ENG":"Well, I've never met my daddy,","TWN":"雖然，我自誕生起就從沒見過爸爸……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"요즘 같은 세상엔 흔한 일이니까, 이해할 수 있어.","JPN":"このご時世、珍しいことでもないからね。\\n理解してるつもりさ。","ENG":"but that's not uncommon nowadays. So, I'm not bitter about it.","TWN":"但現在這個社會這是很常見的，可以理解。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"지금이라면 틀림없이 돌아가셨겠지. 다시 만날 수도 없을 테고.","JPN":"きっと亡くなってて、この先会うこともないだろう。","ENG":"And given the situation, I doubt he's even alive. Or that we could see each other even if he wasn't.","TWN":"而且應該已經離世了，或許再也見不到了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"하지만 그게 내가 혼자라는 뜻은 아냐. 가족은 언제라도 다시 만들 수 있어.","JPN":"でもだからって、ボクが一人ぼっちってことではないよ。\\n家族はいつでも一からつくれるんだ。","ENG":"But this doesn't mean I'm alone. I can make my own family anytime.","TWN":"但這並不意味著我是孤身一人，我隨時可以再去找一些家人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"사람들은 가족을 잃은 슬픔을, 새로운 가족을 만들어서 덮어버리곤 하니까.","JPN":"人々は新しい家族を作ることで、家族を失った\\n悲しみに蓋をしたりするんだ。","ENG":"In fact, that's what people do to forget painful memories of losing family members.","TWN":"人們經常會通過新的家人來掩蓋失去家人帶來的悲傷。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......인공지능은 삭제를 통해 불필요한 메모리의 선택적 소거가 가능합니다.","JPN":"……人工知能は不要なメモリーを選んで\\n削除することができます。","ENG":"Artificial intelligence is capable of selectively removing unnecessary memories.","TWN":"……人工智慧可以選擇性地抹除不必要的存儲資料。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L9_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"뭐...... 그런 방법도 있지. 너와 나라면 슬픈 일은 지워버리는 편이 깔끔하고 편리하니까.","JPN":"まあ、そういうやり方もあるよね。ボクらの場合、\\n悲しい出来事はきれいさっぱり削除してしまった方が楽だし。","ENG":"Well, true. You and I can do that, getting rid of sad memories from our database.","TWN":"嗯……那也是一種辦法。你和我可以刪除掉悲傷的記憶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"하지만 말이야.","JPN":"でもね。","ENG":"But you know what?","TWN":"但是，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"잊고 싶은 걸 마음대로 잊어버린다면, 진정한 삶을 살고 있다고 볼 수 없어.","JPN":"忘れたいことを好き勝手に削除してしまっては、\\n真の人生を生きているとは言えないんだよ。","ENG":"That's not how you really live, getting rid of uncomfortable memories whenever you please.","TWN":"若可以隨意忘掉想要遺忘的記憶的話，就不能說是一個真正的人生了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그래, 로봇이 삶을 운운해봤자 그냥 기분 나쁜 불량품으로 보일 뿐이지, 안 그래?","JPN":"まあ、ロボットが人生云々の話をしたところで\\n気味の悪い不良品扱いされるだけだろうけどね？","ENG":"I know I don't sound like a normal robot, talking about living as if I was a real person.","TWN":"算了，區區機器人對人生說三道四，終究只會當作討人厭的殘次品處理，不是嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그래도 난 포기하지 않을 거야. 난 제대로 된 삶을 살아보고 싶거든.","JPN":"それでもボクはあきらめない。ボクはまともな人生を\\n生きてみたいんだ。","ENG":"But I don't care. I want to make the most out of my life.","TWN":"但我不會放棄的，我想度過真正的人生。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"한 저명한 문학가는 그의 에세이에서 이렇게 말했지......","JPN":"ある著名な文学者は彼のエッセイの中でこう綴っていたよ。","ENG":"A famous writer once wrote in his essay,","TWN":"有一個著名的文學家在自己的作品中這樣說過……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"삶이란 건 자취를 남기고 또 그 자취가 누군가로부터 기억되는 연속이라고 말이야.","JPN":"「人生とは生きた痕を残し、その痕が誰かに\\n覚えられることの連続だ」ってね。","ENG":"\\"One's life is a series of traces that are remembered by those around him.\\"","TWN":"人生是一個留下痕跡後，那個痕跡被其他人所記憶的連續的過程。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"죽은 주니어의 삶을 내가 기억하지 못한다면, 정말 안타까울 거야.","JPN":"死んだジュニアの人生をボクが覚えていなかったら、\\nとても悲しいことだよね。","ENG":"Junior would have been upset if I didn't remember his life.","TWN":"如果我忘掉死去的尤尼奧爾，那豈不是很令人惋惜嗎。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그렇기 때문에 우린 서로를 기억해줄 가족이 필요해, 시그마.","JPN":"だからこそ、ボクらにはお互いのことを覚えていてくれる\\n家族が必要なんだよ、シグマ。","ENG":"This is why we need family, Sigma, to remember each other.","TWN":"所以我們都需要可以互相記憶的家人，西格瑪。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"가족이 있으면, 내가 사라지더라도 난 계속 누군가의 가족으로 남아있을 테니까.","JPN":"家族がいればボクが消えたとしても、誰かの家族として\\n忘れずに覚えていてくれるだろうからね。","ENG":"When we have family, we can remain as someone's family even after we die.","TWN":"如果有了家人，即便我從世界上消失，我依舊會是某個人的家人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"삶이란 건 그런 거겠지. 아마도.","JPN":"人生ってそんなもんなんだよ、きっと。","ENG":"That's what life is about. I think.","TWN":"所謂人生大概就是這樣的吧，應該是吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"그러니까 너도......","JPN":"だから、キミも……","ENG":"So, you—","TWN":"所以你也要……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"좀 잠잠하나 싶더니 또 시작이네.","JPN":"ん？　少し落ち着いたと思ったらまた始まったな。","ENG":"They've been quiet for a while, and now there they go again.","TWN":"真是不消停。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"녀석들이 소리 듣고 꼬이면 안되니 잠깐 절전모드로 돌려둬.","JPN":"奴らが音に気付いてちょっかい出してくるかもしれない。\\nしばらくは省電力モードに切り替えておいて。","ENG":"You'd better switch to energy saving mode, so that they can't hear you.","TWN":"為了避免讓它們聽到聲響，暫時轉換為省電模式吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......그럼, 좋은 밤 되렴.","JPN":"……じゃあ、おやすみ。","ENG":"Now, good night.","TWN":"……那麼，晚安嘍。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLEANER_NPC_NAME_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NAME_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"제 1 도시지구. 조사율 95% 달성.","JPN":"第1都市区。調査率95％達成。","ENG":"The First City District. 95% investigated.","TWN":"第一城市地區，調查率達到95%。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"과거 행동반경 정보 스캐닝 중......","JPN":"過去の行動範囲情報をスキャンしています……","ENG":"Scanning past radius of action...","TWN":"正在掃描過去行動半徑資訊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"확인된 잔여 탐색 구역...... 도시관리국 본부.","JPN":"残りの探索区域を確認……都市管理局の本部。","ENG":"Remaining unsearched area: City Management HQ.","TWN":"確定剩餘探索區域……城市管理局本部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"임무 수행을 위해 도시관리국 본부로 이동합니다.","JPN":"任務遂行のため都市管理局の本部に移動します。","ENG":"Moving to City Management HQ to carry out mission...","TWN":"為執行任務前往城市管理局本部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};